class Solution:
    def getProbability(self, balls):
        from math import comb
        k = len(balls)
        n = sum(balls) // 2
        # enumerate all splits
        favorable = 0.0
        total = 0.0
        def dfs(idx, left1, left2, d1, d2, ways):
            nonlocal favorable, total
            if idx == k:
                if left1 == 0 and left2 == 0:
                    total += ways
                    if d1 == d2:
                        favorable += ways
                return
            b = balls[idx]
            for i in range(b + 1):
                j = b - i
                if i <= left1 and j <= left2:
                    nd1 = d1 + (1 if i > 0 else 0)
                    nd2 = d2 + (1 if j > 0 else 0)
                    dfs(idx + 1, left1 - i, left2 - j, nd1, nd2, ways * comb(b, i))
        dfs(0, n, n, 0, 0, 1.0)
        return favorable / total if total > 0 else 0.0

