class Solution:
    def getProbability(self, balls):
        from math import comb
        from functools import lru_cache
        k = len(balls)
        n = sum(balls) // 2
        @lru_cache(maxsize=None)
        def dp(idx, left1, d1, d2):
            # returns (favorable_ways, total_ways)
            if idx == k:
                left2 = 0  # implied by left1 used up
                if left1 == 0 and d1 == d2:
                    return (1.0, 1.0)
                elif left1 == 0:
                    return (0.0, 1.0)
                else:
                    return (0.0, 0.0)
            b = balls[idx]
            fav = tot = 0.0
            for i in range(b + 1):
                j = b - i
                left2 = n - (sum(balls[:idx]) - (n - left1))
                # compute differently
                if i <= left1:
                    nd1 = d1 + (1 if i > 0 else 0)
                    nd2 = d2 + (1 if j > 0 else 0)
                    w = comb(b, i)
                    sf, st = dp(idx + 1, left1 - i, nd1, nd2)
                    fav += w * sf
                    tot += w * st
            return (fav, tot)
        # Use iterative approach instead for correctness
        k = len(balls)
        n = sum(balls) // 2
        favorable = 0.0
        total = 0.0
        def dfs(idx, left1, left2, d1, d2, ways):
            nonlocal favorable, total
            if idx == k:
                if left1 == 0 and left2 == 0:
                    total += ways
                    if d1 == d2:
                        favorable += ways
                return
            b = balls[idx]
            for i in range(b + 1):
                j = b - i
                if i <= left1 and j <= left2:
                    dfs(idx+1, left1-i, left2-j,
                        d1+(1 if i>0 else 0), d2+(1 if j>0 else 0),
                        ways * comb(b, i))
        dfs(0, n, n, 0, 0, 1.0)
        return favorable / total if total else 0.0

