var getProbability = function(balls) {
    const k = balls.length;
    const n = balls.reduce((a, b) => a + b, 0) / 2;
    function comb(n, r) {
        if (r > n) return 0;
        if (r === 0 || r === n) return 1;
        let res = 1;
        for (let i = 0; i < r; i++) {
            res = res * (n - i) / (i + 1);
        }
        return res;
    }
    let favorable = 0, total = 0;
    function dfs(idx, left1, left2, d1, d2, ways) {
        if (idx === k) {
            if (left1 === 0 && left2 === 0) {
                total += ways;
                if (d1 === d2) favorable += ways;
            }
            return;
        }
        const b = balls[idx];
        for (let i = 0; i <= b; i++) {
            const j = b - i;
            if (i <= left1 && j <= left2) {
                dfs(idx+1, left1-i, left2-j,
                    d1 + (i > 0 ? 1 : 0), d2 + (j > 0 ? 1 : 0),
                    ways * comb(b, i));
            }
        }
    }
    dfs(0, n, n, 0, 0, 1.0);
    return total > 0 ? favorable / total : 0;
};
